// NC
using Content.Shared._NC.Vehicle.Vendor;
using Robust.Client.AutoGenerated;
using Robust.Client.UserInterface.Controls;
using Robust.Client.UserInterface.CustomControls; // For DefaultWindow
using Robust.Client.UserInterface.XAML;
using System.Collections.Generic;

namespace Content.Client._NC.Vehicle.Vendor;

[GenerateTypedNameReferences]
public sealed partial class VehicleVendorMenu : DefaultWindow
{
    private readonly VehicleVendorBoundUserInterface _bui;

    public VehicleVendorMenu(VehicleVendorBoundUserInterface bui)
    {
        RobustXamlLoader.Load(this);
        _bui = bui;
    }

    public void UpdateVehicles(List<VehicleEntry> vehicles)
    {
        VehicleList.RemoveAllChildren();

        foreach (var vehicle in vehicles)
        {
            var box = new BoxContainer
            {
                Orientation = BoxContainer.LayoutOrientation.Horizontal,
                Margin = new Thickness(0, 5)
            };

            var label = new Label
            {
                Text = $"{vehicle.Name} - ${vehicle.Price}",
                HorizontalExpand = true
            };

            var button = new Button
            {
                Text = "Buy",
                MinWidth = 60
            };

            button.OnPressed += _ => _bui.Buy(vehicle.ProtoId);

            box.AddChild(label);
            box.AddChild(button);
            VehicleList.AddChild(box);
        }
    }
}
